import React, { useEffect, useRef } from "react";
import { useNavigate } from "react-router-dom";
import { motion, useAnimation } from "framer-motion";
import "../App.css";

const Home = () => {
  const navigate = useNavigate();
  const controls = useAnimation();
  const lightRef = useRef(null);

  useEffect(() => {
    const animateLight = async () => {
      while (true) {
        await controls.start({ fill: "#e7e5d5" });
        await new Promise((resolve) => setTimeout(resolve, 1000)); // 1 วินาที
        await controls.start({ fill: "#ffe966" });
        await new Promise((resolve) => setTimeout(resolve, 1000)); // 1 วินาที
      }
    };
    animateLight();
  }, [controls]);

  return (
    <div className="background-gradient h-screen flex flex-col justify-center items-center text-center relative">
      {/* ✅ SVG Photobooth */}
      <svg
        className="photoautomat-svg"
        width="300"
        height="400"
        viewBox="0 0 300 400"
        xmlns="http://www.w3.org/2000/svg"
      >
        <image href="/photoautomat.svg" width="300" height="400" />
        {/* ✅ ให้เฉพาะเลเยอร์ "light" เปลี่ยนสี */}
        <motion.circle
          ref={lightRef}
          id="light"
          cx="150"
          cy="50"
          r="20"
          animate={controls}
        />
      </svg>

      {/* ปุ่ม Start */}
      <button onClick={() => navigate("/welcome")} className="start-button">
        START
      </button>
    </div>
  );
};

export default Home;
